// ============================================================
// SISTEMA DE VOZ (Web Speech API - gratis, sin internet)
// ============================================================

// Detectar voces disponibles en español
function getSpanishVoices() {
  if (!('speechSynthesis' in window)) return [];
  const voices = window.speechSynthesis.getVoices();
  return voices.filter(v => v.lang.toLowerCase().startsWith('es'));
}

// Hablar un texto en voz alta
function speakText(text, options = {}) {
  if (!('speechSynthesis' in window)) return;
  // Si está silenciado, no hablar
  const muted = localStorage.getItem('emp:voice_muted') !== 'false';
  if (muted) return;
  // Cancelar mensajes previos
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'es-VE';
  utterance.rate = options.rate || 1.0;
  utterance.pitch = options.pitch || 1.0;
  utterance.volume = options.volume || 1.0;
  // Voz preferida del usuario
  const preferredVoice = localStorage.getItem('emp:voice_name');
  if (preferredVoice) {
    const voices = getSpanishVoices();
    const found = voices.find(v => v.name === preferredVoice);
    if (found) utterance.voice = found;
  }
  window.speechSynthesis.speak(utterance);
}

// Beep de confirmación corto (más sutil que voz)
function playBeep() {
  const muted = localStorage.getItem('emp:voice_muted') !== 'false';
  if (muted) return;
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain); gain.connect(ctx.destination);
    osc.type = 'sine';
    osc.frequency.value = 800;
    gain.gain.setValueAtTime(0.15, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.2);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.2);
  } catch (e) {}
}

// Saludo con hora del día
function getGreetingByTime() {
  const h = new Date().getHours();
  if (h >= 5 && h < 12) return 'Buenos días';
  if (h >= 12 && h < 19) return 'Buenas tardes';
  return 'Buenas noches';
}

// Botón para silenciar/activar voz (visible en barra superior)
function VoiceToggleButton() {
  const [muted, setMuted] = useState(localStorage.getItem('emp:voice_muted') !== 'false');
  const toggle = () => {
    const newMuted = !muted;
    setMuted(newMuted);
    localStorage.setItem('emp:voice_muted', newMuted ? 'true' : 'false');
    // Si acaba de activar, dar feedback
    if (!newMuted) {
      // localStorage cambia el flag muted (debe leer 'false' = no muted)
      setTimeout(() => speakText('Voz activada'), 100);
    } else {
      window.speechSynthesis?.cancel();
    }
  };
  return (
    <button onClick={toggle} title={muted ? 'Activar voz' : 'Silenciar voz'}
      className={`text-sm flex items-center gap-1.5 px-3 py-1.5 rounded-lg transition border ${
        muted
          ? 'bg-white/10 border-white/20 text-stone-300 hover:bg-white/20'
          : 'bg-emerald-500/20 border-emerald-400/40 text-emerald-300 hover:bg-emerald-500/30'
      }`}>
      {muted ? '🔇' : '🔊'} <span className="hidden sm:inline">{muted ? 'Voz off' : 'Voz on'}</span>
    </button>
  );
}

// Botón flotante de "Instalar app" (PWA)
// Aparece cuando el navegador detecta que la app puede instalarse
function InstallAppButton() {
  const [deferredPrompt, setDeferredPrompt] = useState(null);
  const [dismissed, setDismissed] = useState(localStorage.getItem('emp:install_dismissed') === 'true');
  const [installed, setInstalled] = useState(false);

  useEffect(() => {
    // Detectar si ya está instalada (modo standalone)
    if (window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone) {
      setInstalled(true);
      return;
    }

    const handler = (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    const installedHandler = () => {
      setInstalled(true);
      setDeferredPrompt(null);
    };

    window.addEventListener('beforeinstallprompt', handler);
    window.addEventListener('appinstalled', installedHandler);

    return () => {
      window.removeEventListener('beforeinstallprompt', handler);
      window.removeEventListener('appinstalled', installedHandler);
    };
  }, []);

  const handleInstall = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstalled(true);
    }
    setDeferredPrompt(null);
  };

  const handleDismiss = () => {
    setDismissed(true);
    localStorage.setItem('emp:install_dismissed', 'true');
  };

  if (installed || dismissed || !deferredPrompt) return null;

  return (
    <div className="fixed bottom-4 right-4 z-50 max-w-xs animate-pulse">
      <div className="bg-emerald-600 hover:bg-emerald-700 transition rounded-2xl shadow-2xl p-4 border-2 border-emerald-400">
        <button onClick={handleDismiss}
          className="absolute -top-2 -right-2 bg-white text-stone-700 w-7 h-7 rounded-full text-xs font-bold border border-stone-300 hover:bg-stone-100 shadow-md">
          ✕
        </button>
        <div className="flex items-start gap-3">
          <div className="text-3xl">📱</div>
          <div className="flex-1">
            <div className="text-white font-bold text-sm mb-1">Instalar Emporium</div>
            <p className="text-emerald-50 text-xs mb-3 leading-tight">
              Instala la app en tu celular para acceso rápido como aplicación nativa.
            </p>
            <button onClick={handleInstall}
              className="bg-white text-emerald-700 hover:bg-emerald-50 font-bold py-2 px-4 rounded-lg text-sm w-full flex items-center justify-center gap-1.5 shadow-md">
              <Download className="w-4 h-4" /> Instalar
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [view, setView] = useState('welcome');
  const [currentUser, setCurrentUser] = useState(null);
  const [vehicles, setVehicles] = useState(INITIAL_VEHICLES);
  const [drivers, setDrivers] = useState(INITIAL_DRIVERS);
  const [branches, setBranches] = useState(INITIAL_BRANCHES);
  const [trips, setTrips] = useState([]);
  const [activeTrips, setActiveTrips] = useState([]);
  const [archivedMonths, setArchivedMonths] = useState([]);
  const [handoffs, setHandoffs] = useState([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [pendingSyncCount, setPendingSyncCount] = useState(0);
  const [syncMsg, setSyncMsg] = useState(null);
  const [photos, setPhotos] = useState([]);
  const [gpsTracks, setGpsTracks] = useState([]);
  const [checklists, setChecklists] = useState([]);
  const [config, setConfig] = useState(DEFAULT_CONFIG);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const reads = await Promise.all([
          loadFromStorage(KEYS.VEHICLES),
          loadFromStorage(KEYS.DRIVERS),
          loadFromStorage(KEYS.BRANCHES),
          loadFromStorage(KEYS.TRIPS),
          loadFromStorage(KEYS.ACTIVE_TRIPS),
          loadFromStorage(KEYS.ARCHIVED_MONTHS),
          loadFromStorage(KEYS.CONFIG),
          loadFromStorage(KEYS.PHOTOS),
          loadFromStorage(KEYS.GPS_TRACKS),
          loadFromStorage(KEYS.HANDOFFS),
        ]);
        if (reads[0]) setVehicles(reads[0]);
        if (reads[1]) setDrivers(reads[1]);
        if (reads[2]) setBranches(reads[2]);
        if (reads[3]) setTrips(reads[3]);
        if (reads[4]) setActiveTrips(reads[4]);
        if (reads[5]) setArchivedMonths(reads[5]);
        if (reads[6]) setConfig(reads[6]);
        if (reads[7]) setPhotos(reads[7]);
        if (reads[8]) setGpsTracks(reads[8]);
        if (reads[9]) setHandoffs(reads[9]);
        // Cargar checklists desde SUPABASE (sincronizados entre todos los dispositivos)
        const sbData = await loadSBChecklists();
        if (sbData !== null) {
          setChecklists(sbData);
        } else {
          const local = await window.storage.get(KEYS.CHECKLISTS).catch(() => null);
          if (local?.value) setChecklists(JSON.parse(local.value));
        }
      } catch (e) {}
      setLoading(false);
    };
    load();
  }, []);

  // ── Offline-first storage ──────────────────────────────────────────
  const persist = async (key, data) => {
    const serialized = JSON.stringify(data);
    // 1. Guardar en localStorage PRIMERO (siempre funciona, offline o no)
    try { localStorage.setItem(key, serialized); } catch (e) {}
    // 2. Intentar sincronizar con cloud storage
    try {
      await window.storage.set(key, serialized);
      // Éxito: quitar de pendientes
      try {
        const pending = JSON.parse(localStorage.getItem(KEYS.PENDING) || '[]');
        localStorage.setItem(KEYS.PENDING, JSON.stringify(pending.filter(k => k !== key)));
      } catch (e) {}
    } catch (e) {
      // Sin internet: marcar como pendiente de sync
      try {
        const pending = JSON.parse(localStorage.getItem(KEYS.PENDING) || '[]');
        if (!pending.includes(key)) localStorage.setItem(KEYS.PENDING, JSON.stringify([...pending, key]));
      } catch (e2) {}
    }
  };

  const loadFromStorage = async (key) => {
    try {
      const result = await window.storage.get(key);
      if (result?.value) {
        try { localStorage.setItem(key, result.value); } catch (e) {}
        return JSON.parse(result.value);
      }
    } catch (e) {}
    // Fallback: localStorage
    try {
      const local = localStorage.getItem(key);
      return local ? JSON.parse(local) : null;
    } catch (e) { return null; }
  };

  const syncPendingData = async () => {
    // Sync datos al cloud storage
    try {
      const pending = JSON.parse(localStorage.getItem(KEYS.PENDING) || '[]');
      if (pending.length) {
        let synced = 0;
        for (const key of [...pending]) {
          const data = localStorage.getItem(key);
          if (data) {
            try { await window.storage.set(key, data); synced++; } catch (e) { break; }
          }
        }
        if (synced > 0) {
          const remaining = JSON.parse(localStorage.getItem(KEYS.PENDING) || '[]');
          localStorage.setItem(KEYS.PENDING, JSON.stringify(remaining.slice(synced)));
        }
      }
    } catch (e) {}

    // Subir fotos pendientes de IndexedDB
    try {
      const photoQueue = await idbGetAll();
      for (const item of photoQueue) {
        try {
          if (item.type === 'discord') {
            const blob = base64ToBlob(item.photoData);
            const fd = new FormData();
            fd.append('files[0]', blob, item.filename || 'photo.jpg');
            if (item.embed) {
              fd.append('payload_json', JSON.stringify({ embeds: [item.embed] }));
            } else {
              fd.append('payload_json', JSON.stringify({ content: item.content }));
            }
            const res = await fetch(item.webhookUrl, { method: 'POST', body: fd });
            if (res.ok || res.status === 204) {
              await idbDelete(item.id);
            }
          }
        } catch(e) { break; } // Sin internet → parar
      }
    } catch(e) {}

    // Enviar notificaciones Discord pendientes
    try {
      const queue = JSON.parse(localStorage.getItem(KEYS.DISC_QUEUE) || '[]');
      if (!queue.length) return;
      const failed = [];
      for (const item of queue) {
        try {
          const res = await fetch(item.webhookUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ embeds: [item.embed] }),
          });
          if (!res.ok) failed.push(item); // reintentar después
        } catch (e) {
          failed.push(item);
          break; // sin internet, parar
        }
      }
      localStorage.setItem(KEYS.DISC_QUEUE, JSON.stringify(failed));
    } catch (e) {}
  };
  const saveVehicles = (d) => { setVehicles(d); persist(KEYS.VEHICLES, d); };
  const saveDrivers = (d) => { setDrivers(d); persist(KEYS.DRIVERS, d); };
  const saveBranches = (d) => { setBranches(d); persist(KEYS.BRANCHES, d); };
  const saveTrips = (d) => { setTrips(d); persist(KEYS.TRIPS, d); };
  const saveActiveTrips = (d) => { setActiveTrips(d); persist(KEYS.ACTIVE_TRIPS, d); };
  const saveArchived = (d) => { setArchivedMonths(d); persist(KEYS.ARCHIVED_MONTHS, d); };
  const saveConfig = (d) => { setConfig(d); persist(KEYS.CONFIG, d); };
  const savePhotos = (d) => { setPhotos(d); persist(KEYS.PHOTOS, d); };
  const saveGpsTracks = (d) => { setGpsTracks(d); persist(KEYS.GPS_TRACKS, d); };
  const saveHandoffs = (d) => { setHandoffs(d); persist(KEYS.HANDOFFS, d); };
  // saveChecklists: guarda LOCAL siempre + Supabase si está disponible
  const saveChecklists = async (d) => {
    setChecklists(d);
    persist(KEYS.CHECKLISTS, d); // backup local siempre
    if (d.length > 0) {
      const latest = d[d.length - 1];
      saveSBChecklist(latest).catch(() => {}); // Supabase opcional, no bloquea
    }
  };

  // Refrescar checklists desde Supabase cada 30 segundos (para el coordinador)
  // ── Detección online/offline + sync ────────────────────────────────
  useEffect(() => {
    const handleOnline = () => {
      setIsOnline(true);
      setSyncMsg('🔄 Reconectado — sincronizando...');
      syncPendingData().then(() => {
        const pending = JSON.parse(localStorage.getItem(KEYS.PENDING) || '[]');
        setPendingSyncCount(pending.length);
        setSyncMsg(null);
      });
    };
    const handleOffline = () => { setIsOnline(false); setSyncMsg(null); };
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    const pending = JSON.parse(localStorage.getItem(KEYS.PENDING) || '[]');
    setPendingSyncCount(pending.length);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    const poll = async () => {
      const fresh = await loadSBChecklists();
      if (fresh !== null) setChecklists(fresh);
    };
    const interval = setInterval(poll, 30000);
    return () => clearInterval(interval);
  }, []);

  const handleLogin = (role, user) => {
    setCurrentUser(user);
    setView(role);
    // Saludo de voz al hacer login
    const greeting = getGreetingByTime();
    if (role === 'driver') {
      // Saludo + recordatorio de seguridad al chofer
      setTimeout(() => {
        speakText(`${greeting} ${user.shortName}. Recuerda verificar neumáticos, aceite y agua. Límite ochenta kilómetros por hora. Maneja con precaución.`);
      }, 500);
    } else {
      // Saludo cordial al coordinador
      setTimeout(() => {
        speakText(`${greeting} ${user.shortName}. Bienvenido al Sistema de Control de Flota Emporium.`);
      }, 500);
    }
  };
  const handleLogout = () => {
    if ('speechSynthesis' in window) window.speechSynthesis.cancel();
    setCurrentUser(null);
    setView('login');
  };
  const handleWelcomeOk = () => setView('login');

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-[#1a1d1a] to-[#252726] flex items-center justify-center">
        <div className="text-center">
          <img src={LOGO_TRUCK} alt="Transporte Emporium" className="w-32 h-auto mx-auto mb-4 opacity-90 animate-pulse" />
          <div className="text-white font-bold text-lg">Transporte <span className="text-emerald-400">Emporium</span></div>
          <div className="text-stone-400 text-sm mt-1 flex items-center justify-center gap-2">
            <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></div>
            Cargando...
          </div>
        </div>
      </div>
    );
  }

  const OfflineBanner = () => (
    <>
      {!isOnline && (
        <div className="fixed top-0 left-0 right-0 z-[999] bg-amber-500 text-white text-center text-xs py-1.5 font-bold shadow-lg">
          📡 Sin conexión — datos guardados localmente, se sincronizarán al reconectar
        </div>
      )}
      {isOnline && syncMsg && (
        <div className="fixed top-0 left-0 right-0 z-[999] bg-blue-600 text-white text-center text-xs py-1.5 font-bold shadow-lg animate-pulse">
          {syncMsg}
        </div>
      )}
      {isOnline && !syncMsg && pendingSyncCount > 0 && (
        <div className="fixed top-0 left-0 right-0 z-[999] bg-emerald-600 text-white text-center text-xs py-1.5 font-bold shadow-lg">
          ✅ Sincronizado — {pendingSyncCount === 0 ? 'todo al día' : `${pendingSyncCount} cambios pendientes`}
        </div>
      )}
    </>
  );

  if (view === 'welcome') return <><OfflineBanner /><WelcomeScreen onOk={handleWelcomeOk} /><InstallAppButton /></>;
  if (view === 'login') return <><LoginScreen drivers={drivers} onLogin={handleLogin} /><InstallAppButton /></>;

  if (view === 'driver') {
    return <><OfflineBanner />
      <DriverApp
        currentDriver={currentUser} onLogout={handleLogout}
        vehicles={vehicles} drivers={drivers} branches={branches}
        trips={trips} activeTrips={activeTrips} photos={photos} gpsTracks={gpsTracks}
        saveTrips={saveTrips} saveActiveTrips={saveActiveTrips} saveVehicles={saveVehicles}
        savePhotos={savePhotos} saveGpsTracks={saveGpsTracks}
        checklists={checklists} saveChecklists={saveChecklists}
        config={config}
        handoffs={handoffs} saveHandoffs={saveHandoffs}
      />
      <InstallAppButton />
    </>;
  }

  if (view === 'coordinator') {
    return <><OfflineBanner />
      <CoordinatorApp
        onLogout={handleLogout}
        vehicles={vehicles} drivers={drivers} branches={branches}
        trips={trips} activeTrips={activeTrips} archivedMonths={archivedMonths} photos={photos} gpsTracks={gpsTracks}
        config={config}
        checklists={checklists}
        handoffs={handoffs}
        saveVehicles={saveVehicles} saveDrivers={saveDrivers} saveBranches={saveBranches}
        saveTrips={saveTrips} saveActiveTrips={saveActiveTrips} saveGpsTracks={saveGpsTracks}
        saveArchived={saveArchived} saveConfig={saveConfig} savePhotos={savePhotos}
      />
      <InstallAppButton />
    </>;
  }
  return null;
}

