// PANTALLA DE BIENVENIDA (con contraseña general)
// ============================================================
function WelcomeScreen({ onOk }) {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricRegistered, setBiometricRegistered] = useState(false);
  const [biometricLoading, setBiometricLoading] = useState(false);

  useEffect(() => {
    const check = async () => {
      if (window.PublicKeyCredential) {
        const ok = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
        setBiometricAvailable(ok);
        setBiometricRegistered(!!localStorage.getItem('emp:biometric:credId'));
      }
    };
    check();
  }, []);

  const tryEnter = () => {
    if (password.toLowerCase().trim() === GLOBAL_PASSWORD) {
     // 🔊 SALUDO al ingresar contraseña general correctamente
        const greeting = getGreetingByTime();
        setTimeout(() => {
          speakText(`${greeting}. Bienvenido al Sistema de Control de Flota Emporium.`);
        }, 300);
      onOk();
    } else {
      setError('Contraseña incorrecta');
      setPassword('');
    }
  };

  const registerBiometric = async () => {
    setBiometricLoading(true);
    try {
      const challenge = new Uint8Array(32);
      crypto.getRandomValues(challenge);
      const cred = await navigator.credentials.create({ publicKey: { challenge, rp: { name: 'Transporte Emporium', id: location.hostname }, user: { id: new Uint8Array(16), name: 'usuario', displayName: 'Usuario' }, pubKeyCredParams: [{ type: 'public-key', alg: -7 }], authenticatorSelection: { authenticatorAttachment: 'platform', userVerification: 'required' }, timeout: 30000 } });
      localStorage.setItem('emp:biometric:credId', btoa(String.fromCharCode(...new Uint8Array(cred.rawId))));
      setBiometricRegistered(true);
      alert('Huella registrada correctamente');
    } catch (e) { alert('No se pudo registrar: ' + e.message); }
    setBiometricLoading(false);
  };
  const loginBiometric = async () => {
    setBiometricLoading(true);
    try {
      const challenge = new Uint8Array(32);
      crypto.getRandomValues(challenge);
      const credIdStr = localStorage.getItem('emp:biometric:credId');
      const credIdBytes = Uint8Array.from(atob(credIdStr), c => c.charCodeAt(0));
      await navigator.credentials.get({ publicKey: { challenge, rpId: location.hostname, allowCredentials: [{ type: 'public-key', id: credIdBytes }], userVerification: 'required', timeout: 30000 } });
      const greeting = getGreetingByTime();
      setTimeout(() => speakText(greeting + '. Bienvenido al Sistema de Control de Flota Emporium.'), 300);
      onOk();
    } catch (e) { setError('Huella no reconocida. Usa tu contrasena.'); }
    setBiometricLoading(false);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 relative overflow-hidden"
      style={{ background: 'linear-gradient(135deg, #fef3c7 0%, #fde68a 50%, #f59e0b 100%)' }}>
      {/* Patrón decorativo */}
      <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(circle, #78350f 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>

      {/* Círculos decorativos */}
      <div className="absolute top-0 right-0 w-96 h-96 rounded-full opacity-20 blur-3xl" style={{ background: '#10b981' }}></div>
      <div className="absolute bottom-0 left-0 w-96 h-96 rounded-full opacity-20 blur-3xl" style={{ background: '#f59e0b' }}></div>

      <div className="w-full max-w-md relative z-10">
        {/* Logo y nombre */}
        <div className="text-center mb-8">
          <div className="bg-white rounded-3xl p-6 shadow-2xl mb-5 inline-block transform hover:scale-105 transition-transform">
            <img src={LOGO_TRUCK} alt="Transporte Emporium" className="w-56 h-auto mx-auto" />
          </div>
          <h1 className="text-5xl font-black tracking-tight leading-none drop-shadow-sm" style={{ letterSpacing: '-0.03em' }}>
            <span style={{ color: '#047857' }}>Transporte</span>
          </h1>
          <h1 className="text-5xl font-black tracking-tight leading-none drop-shadow-sm mt-1" style={{ letterSpacing: '-0.03em' }}>
            <span style={{ color: '#047857' }}>Emporium</span>
          </h1>
          <p className="text-stone-700 text-sm mt-3 font-semibold">Sistema de Control de Flota</p>
        </div>

        {/* Tarjeta de contraseña */}
        <div className="bg-white rounded-3xl p-6 shadow-2xl">
          <div className="text-center mb-4">
            <div className="inline-flex items-center justify-center w-14 h-14 bg-emerald-100 rounded-2xl mb-3">
              <Lock className="w-7 h-7 text-emerald-700" />
            </div>
            <h2 className="font-bold text-stone-900 text-lg">Acceso a la aplicación</h2>
            <p className="text-sm text-stone-600 mt-1">Ingresa la contraseña para continuar</p>
          </div>

          <div className="relative mb-3">
            <input
              type={showPassword ? 'text' : 'password'}
              value={password}
              onChange={e => { setPassword(e.target.value); setError(''); }}
              onKeyDown={e => e.key === 'Enter' && tryEnter()}
              placeholder="Contraseña"
              autoFocus
              className="w-full px-4 py-3.5 pr-12 bg-stone-50 border-2 border-stone-200 rounded-xl text-base text-stone-900 placeholder:text-stone-400 outline-none focus:border-emerald-600 focus:bg-white transition"
            />
            <button onClick={() => setShowPassword(!showPassword)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-500 hover:text-stone-700 text-xs font-semibold">
              {showPassword ? '🙈' : '👁️'}
            </button>
          </div>

          {error && (
            <div className="bg-rose-50 border border-rose-200 text-rose-700 text-sm rounded-lg px-3 py-2 mb-3 text-center font-medium">
              {error}
            </div>
          )}

          {biometricAvailable && biometricRegistered && <button onClick={loginBiometric} disabled={biometricLoading} className="w-full py-3 rounded-xl font-bold text-white bg-emerald-600 hover:bg-emerald-700 shadow-lg flex items-center justify-center gap-2 mb-2">{biometricLoading ? 'Verificando...' : 'Entrar con huella'}</button>}
          {biometricAvailable && !biometricRegistered && <button onClick={registerBiometric} disabled={biometricLoading} className="w-full py-2 rounded-xl font-semibold text-emerald-700 bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 flex items-center justify-center gap-2 mb-2">{biometricLoading ? 'Registrando...' : 'Activar huella dactilar'}</button>}
          <button onClick={tryEnter} disabled={!password}
            className={`w-full py-3.5 rounded-xl font-bold text-white transition-all flex items-center justify-center gap-2 ${password ? 'bg-emerald-600 hover:bg-emerald-700 shadow-lg active:scale-[0.98]' : 'bg-stone-300'}`}>
            Entrar <ChevronRight className="w-5 h-5" />
          </button>
        </div>

        <div className="text-center mt-5 text-stone-700 text-xs font-semibold opacity-70">
          v6.0 · Edición Profesional
        </div>
      </div>
    </div>
  );
}

