function PhotoCapture({ onCapture, onCancel }) {
  const fileInputRef = useRef(null);
  const [category, setCategory] = useState(PHOTO_CATEGORIES[0].id);
  const [description, setDescription] = useState('');
  const [imageData, setImageData] = useState(null);

  const handleFile = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const maxDim = 1200;
        let w = img.width, h = img.height;
        if (w > h && w > maxDim) { h = (h * maxDim) / w; w = maxDim; }
        else if (h > maxDim) { w = (w * maxDim) / h; h = maxDim; }
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        setImageData(canvas.toDataURL('image/jpeg', 0.7));
      };
      img.src = ev.target.result;
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-4">
      <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
        <div className="flex items-center justify-between mb-3">
          <h2 className="font-bold text-stone-900 uppercase tracking-wider font-mono text-sm">📷 Tomar foto</h2>
          <button onClick={onCancel} className="text-emerald-700 hover:text-stone-700"><X className="w-5 h-5" /></button>
        </div>

        <label className="text-[11px] font-bold text-stone-600 mb-2 block uppercase tracking-wider font-mono">Tipo</label>
        <div className="grid grid-cols-2 gap-2 mb-4">
          {PHOTO_CATEGORIES.map(c => {
            const Icon = c.icon;
            return (
              <button key={c.id} onClick={() => setCategory(c.id)}
                className={`p-3 rounded-lg border-2 flex items-center gap-2 text-sm transition ${category === c.id ? 'border-emerald-400 bg-emerald-500/15 text-stone-900' : 'border-stone-200 text-emerald-700 bg-stone-50'}`}>
                <Icon className="w-4 h-4" />
                <span className="font-medium text-left">{c.label}</span>
              </button>
            );
          })}
        </div>

        {!imageData ? (
          <button onClick={() => fileInputRef.current?.click()}
            className="w-full py-12 rounded-xl border-2 border-dashed border-stone-300 hover:border-emerald-500 hover:bg-stone-50 transition flex flex-col items-center gap-2 text-emerald-700">
            <Camera className="w-10 h-10" />
            <span className="font-bold">Tomar foto o subir</span>
            <span className="text-xs text-stone-500 font-mono uppercase">Cámara o galería</span>
          </button>
        ) : (
          <div className="space-y-2">
            <img src={imageData} alt="" className="w-full rounded-lg max-h-80 object-contain bg-black" />
            <button onClick={() => setImageData(null)} className="text-sm text-rose-400">Cambiar foto</button>
          </div>
        )}

        <input ref={fileInputRef} type="file" accept="image/*" capture="environment" onChange={handleFile} className="hidden" />

        <div className="mt-4">
          <DarkField label="Descripción (opcional)">
            <input value={description} onChange={e => setDescription(e.target.value)} placeholder="Ej: Transferencia #12345" className="dark-input" />
          </DarkField>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-2">
        <button onClick={onCancel} className="py-3 rounded-xl font-medium text-emerald-700 bg-stone-100 border border-stone-200">Cancelar</button>
        <button onClick={() => onCapture({ category, description, imageData })} disabled={!imageData}
          className={`py-3 rounded-xl font-bold text-white shadow-lg flex items-center justify-center gap-2 ${imageData ? 'bg-gradient-to-r from-emerald-600 to-emerald-700' : 'bg-stone-100 text-stone-300'}`}>
          <Save className="w-5 h-5" /> Guardar
        </button>
      </div>
      <DarkInputStyles />
    </div>
  );
}

function PhotosView({ photos, vehicles, drivers = [], onAdd, onDelete, canAdd, showDriver = false }) {
  const [showCamera, setShowCamera] = useState(false);
  const [filter, setFilter] = useState('all');
  const [viewing, setViewing] = useState(null);

  if (showCamera) return <PhotoCapture onCapture={(p) => { onAdd(p); setShowCamera(false); }} onCancel={() => setShowCamera(false)} />;

  const filtered = filter === 'all' ? photos : photos.filter(p => p.category === filter);
  const grouped = useMemo(() => {
    const byKey = {};
    filtered.forEach(p => {
      const key = showDriver ? `${p.date}|${p.driverId}` : p.date;
      if (!byKey[key]) byKey[key] = [];
      byKey[key].push(p);
    });
    return Object.entries(byKey).sort((a, b) => b[0].localeCompare(a[0]));
  }, [filtered, showDriver]);

  return (
    <div className="space-y-3">
      {viewing && (
        <div className="fixed inset-0 bg-black/95 z-50 flex items-center justify-center p-4" onClick={() => setViewing(null)}>
          <button onClick={() => setViewing(null)} className="absolute top-4 right-4 text-stone-700"><X className="w-8 h-8" /></button>
          <img src={viewing.imageData} alt="" className="max-w-full max-h-full object-contain" />
        </div>
      )}

      {canAdd && (
        <button onClick={() => setShowCamera(true)}
          className="w-full py-4 rounded-2xl font-bold text-white bg-gradient-to-r from-emerald-600 to-emerald-700 shadow-lg shadow-emerald-700/30 flex items-center justify-center gap-2">
          <Camera className="w-5 h-5" /> Tomar nueva foto
        </button>
      )}

      <div className="flex gap-1 overflow-x-auto -mx-1 px-1">
        <DarkFilterChip active={filter === 'all'} onClick={() => setFilter('all')} label={`Todas (${photos.length})`} />
        {PHOTO_CATEGORIES.map(c => {
          const count = photos.filter(p => p.category === c.id).length;
          return <DarkFilterChip key={c.id} active={filter === c.id} onClick={() => setFilter(c.id)} label={`${c.label} (${count})`} />;
        })}
      </div>

      {grouped.length === 0 && (
        <div className="bg-white rounded-xl p-8 text-center text-stone-400 border border-stone-200">
          <ImageIcon className="w-10 h-10 mx-auto mb-2 opacity-50" />
          <div className="text-sm">No hay fotos</div>
        </div>
      )}

      {grouped.map(([key, items]) => {
        const [date, driverId] = key.split('|');
        const driver = drivers.find(d => d.id === driverId);
        const dateLabel = new Date(date + 'T00:00:00').toLocaleDateString('es-VE', { weekday: 'long', day: 'numeric', month: 'long' });
        return (
          <div key={key} className="bg-white rounded-xl border border-stone-200 overflow-hidden shadow-sm">
            <div className="px-4 py-2 bg-stone-100 border-b border-stone-200 text-xs font-bold text-emerald-700 capitalize flex items-center justify-between font-mono uppercase tracking-wider">
              <span>{dateLabel}</span>
              {showDriver && driver && <span className="text-stone-700">{driver.shortName}</span>}
            </div>
            <div className="grid grid-cols-3 gap-1 p-1">
              {items.map(p => {
                const cat = PHOTO_CATEGORIES.find(c => c.id === p.category);
                const v = vehicles.find(x => x.id === p.vehicleId);
                return (
                  <div key={p.id} className="relative group aspect-square">
                    <img src={p.imageData} alt="" onClick={() => setViewing(p)} className="w-full h-full object-cover rounded cursor-pointer" />
                    <div className="absolute top-1 left-1 bg-black/70 backdrop-blur text-stone-700 text-[9px] px-1.5 py-0.5 rounded font-mono uppercase">{cat?.label.split('/')[0]}</div>
                    {v && <div className="absolute bottom-1 left-1 bg-emerald-600/90 text-white text-[9px] px-1.5 py-0.5 rounded font-mono">{v.code}</div>}
                    {onDelete && (
                      <button onClick={() => { if (confirm('¿Eliminar?')) onDelete(p.id); }} className="absolute top-1 right-1 bg-rose-600 text-white p-1 rounded opacity-0 group-hover:opacity-100">
                        <Trash2 className="w-3 h-3" />
                      </button>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function DarkFilterChip({ active, onClick, label }) {
  return (
    <button onClick={onClick} className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition font-mono uppercase tracking-wider ${active ? 'bg-emerald-500 text-white' : 'bg-stone-100 text-emerald-700 border border-stone-200'}`}>
      {label}
    </button>
  );
}

function DriverHistoryView({ trips, vehicles, branches }) {
  const sorted = [...trips].sort((a, b) => b.createdAt - a.createdAt);
  if (sorted.length === 0) {
    return (
      <div className="bg-white rounded-xl p-8 text-center text-stone-400 border border-stone-200">
        <Route className="w-10 h-10 mx-auto mb-2 opacity-50" />
        <div className="text-sm">Aún no tienes viajes registrados</div>
      </div>
    );
  }
  return (
    <div className="space-y-2">
      <div className="bg-stone-100 border border-stone-300 rounded-xl p-3 text-sm">
        <div className="font-bold text-stone-900 font-mono">TOTAL: {sorted.length} VIAJES</div>
        <div className="text-xs text-stone-600 mt-1 font-mono">
          {sorted.reduce((s, t) => s + t.kmTraveled, 0).toLocaleString()} km · {sorted.reduce((s, t) => s + t.deliveries, 0)} entregas
        </div>
      </div>
      {sorted.map(t => {
        const v = vehicles.find(x => x.id === t.vehicleId);
        const o = branches.find(x => x.id === t.originBranchId);
        const d = branches.find(x => x.id === t.destinationBranchId);
        return (
          <div key={t.id} className="bg-white rounded-xl border border-stone-200 shadow-sm p-3 text-sm">
            <div className="flex justify-between items-start mb-2">
              <div>
                <div className="font-bold text-stone-900">{v?.code}</div>
                <div className="text-xs text-stone-500 font-mono">{t.startDate}</div>
              </div>
              <div className="text-right">
                <div className="text-xs text-stone-500 font-mono">{t.startTime} → {t.endTime}</div>
                <div className="text-xs font-bold text-amber-400 font-mono">{formatDuration(t.tripMinutes)}</div>
              </div>
            </div>
            <div className="text-xs flex items-center gap-1 text-stone-700">
              <span>{o?.name}</span><ArrowRight className="w-3 h-3 text-emerald-700" /><span>{d?.name}</span>
            </div>
            <div className="grid grid-cols-3 gap-2 mt-2 text-xs">
              <div className="bg-stone-100 rounded p-1.5"><div className="text-stone-500 font-mono uppercase tracking-wider text-[9px]">KM</div><div className="font-bold text-stone-900">{t.kmTraveled}</div></div>
              <div className="bg-stone-100 rounded p-1.5"><div className="text-stone-500 font-mono uppercase tracking-wider text-[9px]">Litros</div><div className="font-bold text-stone-900">{t.liters.toFixed(1)}</div></div>
              <div className="bg-stone-100 rounded p-1.5"><div className="text-stone-500 font-mono uppercase tracking-wider text-[9px]">Entregas</div><div className="font-bold text-stone-900">{t.deliveries}</div></div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

